def _fmt(x):
    if abs(x - round(x)) < 0.0005:
        return '%d' % round(x)
    return ('%.3f' % x).rstrip('0').rstrip('.')


def entries(patch):
    """[(note, midi_note_cmd)] capped io note maps for a sampled kit
    patch, or [] if not a sampled kit. drums_kit re-sends each on the
    live DrumSynth to override the too-loud baked velscales. Field layout
    matches the baked entries: note,0,0,cappedscale,0,v<osc>n<base>l%vi%i."""
    out = []
    for note, osc, base, capped in CAPS.get(patch, ()):  # noqa
        out.append((note, '%d,0,0,%s,0,v%dn%dl%%vi%%i'
                    % (note, _fmt(capped), osc, base)))
    return out
